        height: GAP_HEIGHT,
        background: bg,
        display: 'flex',
        alignItems: 'center',
        paddingLeft: ITEM_PADDING,
        paddingRight: ITEM_PADDING,
        cursor: 'pointer',
      }}
    >
      {isSplit && (
        <div style={{ flex: 1, height: 2, background: 'var(--mantine-color-blue-5)', borderRadius: 1 }} />
      )}
      {!isSplit && isHovered && (
